import { useMemo } from 'react';

import type { ColorRuleProps } from '../../../core/types/color-rule.js';
import type { HistogramChartProps } from '../../../histogram/types/histogram-props.js';
import { HISTOGRAM_DEFAULT_VALUE_ACCESSOR } from '../utils/get-subject-for-series.js';
import { resolveHistogramColorRules } from '../utils/resolve-histogram-color-rules.js';

type UseHistogramToXYColorRulesParams = {
  data: HistogramChartProps['data'];
  seriesColors: Array<{ name: string; color: string }>;
  colorRules: ColorRuleProps[];
};

/**
 * Builds the final list of XYChart-compatible color rules for the
 * HistogramToXY adoption component.
 *
 * Priority (last matching rule wins in XYChart):
 *   colorPalette (lowest) < color in data < ColorRule (highest)
 *
 * Series data colors are placed first so user-defined ColorRules can
 * override them.
 */
export function useHistogramToXYColorRules({
  data,
  seriesColors,
  colorRules,
}: UseHistogramToXYColorRulesParams): ColorRuleProps[] {
  return useMemo(() => {
    const dataColorRules: ColorRuleProps[] = seriesColors.map(
      ({ name, color }) => ({
        comparator: 'equals' as const,
        matchValue: name,
        color,
        valueAccessor: HISTOGRAM_DEFAULT_VALUE_ACCESSOR,
      }),
    );

    const resolvedUserRules = resolveHistogramColorRules(data, colorRules);

    return [...dataColorRules, ...resolvedUserRules];
  }, [seriesColors, colorRules, data]);
}
